// GRADE_v1 (v0.3) - certitude des preuves par outcome (Summary of Findings).
// Consomme les sorties meta-analyse (_meta_summary : I2, IC groupe, Egger, k) et RoB (_rob_level)
// si presentes dans le corpus ; 1 appel LLM pour le caractere indirect (et le risque de biais si pas de RoB).
const PROXY = 'http://host.docker.internal:3456';
const items = $input.all();
const articles = items.map(i => i.json);
const a0 = articles[0] || {};
const QUESTION = (a0.question || a0._meta_outcome || '').toString();
const ms = a0._meta_summary || null;
console.log('[GRADE] ' + articles.length + ' etudes, meta=' + (!!ms) );

function extractJson(raw){ if(!raw) return null; let s=String(raw).replace(/```json/gi,'').replace(/```/g,''); const i=s.indexOf('{'),j=s.lastIndexOf('}'); if(i<0||j<=i) return null; const f=s.substring(i,j+1); try{return JSON.parse(f);}catch(e){} try{return JSON.parse(f.replace(/,\s*([}\]])/g,'$1'));}catch(e){} return null; }
function detectDesign(a){ const t=((a.title||'')+' '+(a.abstract||'')).toLowerCase(); if(/randomi[sz]ed[^.]{0,20}(controlled )?trial|\brct\b|randomi[sz]ed[^.]{0,20}(study|design)|randomly (assigned|allocated)|double-blind|placebo-controlled/.test(t)) return 'rct'; if(/cohort|case-control|case control|observational|cross-sectional|registry|retrospective|prospective (cohort|study)|non-randomi/.test(t)) return 'nonrandomized'; return 'unknown'; }

// devis majoritaire (heuristique ; secours = LLM si tout 'unknown')
let nrct=0,nnr=0; for(const a of articles){ const d=detectDesign(a); if(d==='rct')nrct++; else if(d==='nonrandomized')nnr++; }
let design = (nrct>=nnr && nrct>0) ? 'rct' : (nnr>0 ? 'nonrandomized' : 'unknown');

// signal risque de biais depuis le module RoB si present
let robN=0, robHigh=0; for(const a of articles){ if(a._rob_level){ robN++; if(a._rob_level==='high')robHigh++; } }
const robProp = robN ? robHigh/robN : null;

// 1 appel LLM : caractere indirect (+ risque de biais si pas de donnees RoB)
const titles = articles.map(function(a){return (a.title||'').substring(0,90);}).filter(Boolean).slice(0,8);
let llm = { indirectness:'none', indirectness_reason:'', risk_of_bias:'low', rob_reason:'' };
try {
  const prompt = [
    'You are applying the GRADE approach. Judge the body of evidence answering this question.',
    'QUESTION: ' + QUESTION.substring(0,300),
    'Number of studies: ' + articles.length + '. Predominant design: ' + design + '.',
    'Sample study titles:', titles.join('\n'),
    '',
    'Return STRICT JSON ONLY:',
    '{ "design": "rct" | "nonrandomized", "indirectness": "none" | "serious", "indirectness_reason": "<short>", "risk_of_bias": "low" | "some" | "high", "rob_reason": "<short>" }',
    'design = predominant study design of this body of evidence.',
    'Indirectness = PICO mismatch with the question (different population/intervention/comparator, or only surrogate/indirect outcomes).',
    'risk_of_bias = your overall impression of study quality from the titles/design (used only if no formal RoB data).'
  ].join('\n');
  const rp = await this.helpers.httpRequest({ method:'POST', url:PROXY+'/api/generate', body:JSON.stringify({ model:'qwen2.5:3b', prompt:prompt, stream:false, format:'json', options:{temperature:0,num_predict:300,num_ctx:8192}, keep_alive:'30m', _ultralab_task:'chat' }), headers:{'Content-Type':'application/json'}, json:true, timeout:900000 });
  const p = extractJson((rp&&rp.response)||''); if(p) llm=Object.assign(llm,p);
} catch(e) { console.log('[GRADE] llm err ' + e.message); }

// devis : secours LLM si l'heuristique n'a rien trouve
if (design==='unknown') design = (llm.design==='rct'||llm.design==='nonrandomized') ? llm.design : 'nonrandomized';

const start = (design==='rct') ? 4 : 2;
let downs=0, ups=0; const domains={}; const upNotes=[];

// 1. Risque de biais
if (robProp!=null){ if(robProp>0.5){ domains.risk_of_bias={rating:'serious (-1)',note:'module RoB : '+robHigh+'/'+robN+' a risque eleve'}; downs-=1; } else domains.risk_of_bias={rating:'not serious',note:'module RoB : '+robHigh+'/'+robN+' a risque eleve'}; }
else { if((llm.risk_of_bias||'')==='high'){ domains.risk_of_bias={rating:'serious (-1)',note:'jugement IA : '+(llm.rob_reason||'')}; downs-=1; } else domains.risk_of_bias={rating:'not serious',note:'jugement IA (pas de run RoB) : '+(llm.rob_reason||'')}; }

// 2. Incoherence (I2)
if (ms && ms.heterogeneity){ const i2=ms.heterogeneity.I2; if(i2>=50){ domains.inconsistency={rating:'serious (-1)',note:'I2='+i2+'%'}; downs-=1; } else domains.inconsistency={rating:'not serious',note:'I2='+i2+'%'}; }
else domains.inconsistency={rating:'non evaluable',note:'pas de meta-analyse en entree (lancer le module meta-analyse d abord)'};

// 3. Imprecision (IC groupe / nb d etudes)
if (ms && ms.random){ const lo=ms.random.ci_low, hi=ms.random.ci_high, nv=(ms.null_value!=null?ms.null_value:(ms.is_log?1:0)); const crosses=(lo<=nv && hi>=nv); if(crosses){ domains.imprecision={rating:'serious (-1)',note:'IC95% franchit le nul ['+lo+', '+hi+']'}; downs-=1; } else if((ms.k||0)<4){ domains.imprecision={rating:'serious (-1)',note:'peu d etudes (k='+ms.k+')'}; downs-=1; } else domains.imprecision={rating:'not serious',note:'IC95% ['+lo+', '+hi+'], k='+ms.k}; }
else domains.imprecision={rating:'non evaluable',note:'pas de meta-analyse en entree'};

// 4. Caractere indirect (LLM)
if ((llm.indirectness||'')==='serious'){ domains.indirectness={rating:'serious (-1)',note:llm.indirectness_reason||'jugement IA (PICO vs question)'}; downs-=1; }
else domains.indirectness={rating:'not serious',note:llm.indirectness_reason||'jugement IA (PICO vs question)'};

// 5. Biais de publication (Egger / k)
if (ms && ms.egger){ const t=Math.abs(ms.egger.t||0); if(t>=1.96){ domains.publication_bias={rating:'suspected (-1)',note:'test d Egger t='+ms.egger.t}; downs-=1; } else domains.publication_bias={rating:'undetected',note:'test d Egger t='+ms.egger.t}; }
else if (ms && ms.k!=null && ms.k<10) domains.publication_bias={rating:'undetected',note:'k<10 : funnel peu informatif'};
else domains.publication_bias={rating:'non evaluable',note:'pas de meta-analyse en entree'};

// Reclassement (observationnel uniquement, effet large)
if (design==='nonrandomized' && ms && ms.random && ms.is_log){ const e=ms.random.effect; if(e>0){ if(e<0.2||e>5){ ups+=2; upNotes.push('effet tres large (RR/OR '+e+')'); } else if(e<0.5||e>2){ ups+=1; upNotes.push('effet large (RR/OR '+e+')'); } } }

let lvl=start+downs+ups; if(lvl<1)lvl=1; if(lvl>4)lvl=4;
const certaintyMap={4:'high',3:'moderate',2:'low',1:'very low'};
const certaintyFr={high:'Élevée',moderate:'Modérée',low:'Faible','very low':'Très faible'};
const certainty=certaintyMap[lvl];

a0._grade_summary = {
  outcome: (ms&&ms.outcome) || QUESTION || '(outcome principal)',
  design: design,
  start_level: (design==='rct')?'Élevée (ECR)':'Faible (observationnel)',
  downgrades: -downs, upgrades: ups,
  certainty: certainty, certainty_fr: certaintyFr[certainty], certainty_symbol: '⊕'.repeat(lvl)+'⊖'.repeat(4-lvl),
  domains: domains, k: ms?ms.k:articles.length,
  pooled: ms?ms.random:null, measure: ms?ms.measure:null,
  used_meta: !!ms, used_rob: (robProp!=null), upgrade_notes: upNotes
};
console.log('[GRADE] certitude=' + certainty + ' (start '+start+' down '+downs+' up '+ups+')');
return articles.map(function(x){ return { json:x }; });
